import grpc
from concurrent import futures
import time
import auth_service_pb2
import auth_service_pb2_grpc
import data_service_pb2
import data_service_pb2_grpc
import secrets
import hashlib


class AuthServiceServicer(auth_service_pb2_grpc.AuthServiceServicer):
    def __init__(self):
        self.users = {
            'admin': hashlib.sha256('admin123'.encode()).hexdigest(),
            'user1': hashlib.sha256('password1'.encode()).hexdigest()
        }
        self.tokens = {}

    def Login(self, request, context):
        username = request.username
        password = hashlib.sha256(request.password.encode()).hexdigest()
        
        if username in self.users and self.users[username] == password:
            token = secrets.token_urlsafe(32)
            self.tokens[token] = username
            return auth_service_pb2.LoginResponse(
                success=True,
                token=token,
                message="Login successful"
            )
        else:
            return auth_service_pb2.LoginResponse(
                success=False,
                token="",
                message="Invalid credentials"
            )

    def ValidateToken(self, request, context):
        token = request.token
        if token in self.tokens:
            return auth_service_pb2.ValidateTokenResponse(
                valid=True,
                username=self.tokens[token]
            )
        else:
            return auth_service_pb2.ValidateTokenResponse(
                valid=False,
                username=""
            )


class DataServiceServicer(data_service_pb2_grpc.DataServiceServicer):
    def __init__(self, auth_servicer):
        self.auth_servicer = auth_servicer
        self.user_data = {
            'admin': '{"role": "administrator", "email": "admin@example.com"}',
            'user1': '{"role": "user", "email": "user1@example.com"}'
        }

    def GetUserData(self, request, context):
        token_valid = self.auth_servicer.ValidateToken(
            auth_service_pb2.ValidateTokenRequest(token=request.token),
            context
        )
        
        if not token_valid.valid:
            return data_service_pb2.GetUserDataResponse(
                success=False,
                data="",
                message="Invalid token"
            )
        
        user_id = request.user_id
        if user_id in self.user_data:
            return data_service_pb2.GetUserDataResponse(
                success=True,
                data=self.user_data[user_id],
                message="Data retrieved successfully"
            )
        else:
            return data_service_pb2.GetUserDataResponse(
                success=False,
                data="",
                message="User not found"
            )

    def UpdateUserData(self, request, context):
        token_valid = self.auth_servicer.ValidateToken(
            auth_service_pb2.ValidateTokenRequest(token=request.token),
            context
        )
        
        if not token_valid.valid:
            return data_service_pb2.UpdateUserDataResponse(
                success=False,
                message="Invalid token"
            )
        
        user_id = request.user_id
        self.user_data[user_id] = request.data
        return data_service_pb2.UpdateUserDataResponse(
            success=True,
            message="Data updated successfully"
        )


def serve():
    server = grpc.server(futures.ThreadPoolExecutor(max_workers=10))
    
    auth_servicer = AuthServiceServicer()
    data_servicer = DataServiceServicer(auth_servicer)
    
    auth_service_pb2_grpc.add_AuthServiceServicer_to_server(auth_servicer, server)
    data_service_pb2_grpc.add_DataServiceServicer_to_server(data_servicer, server)
    
    # Load TLS credentials
    with open('server.key', 'rb') as f:
        private_key = f.read()
    with open('server.crt', 'rb') as f:
        certificate_chain = f.read()
    with open('ca.crt', 'rb') as f:
        root_certificates = f.read()
    
    server_credentials = grpc.ssl_server_credentials(
        [(private_key, certificate_chain)],
        root_certificates=root_certificates,
        require_client_auth=True
    )
    
    server.add_secure_port('[::]:50051', server_credentials)
    server.start()
    print("Secure gRPC server started on port 50051 with mutual TLS")
    
    try:
        while True:
            time.sleep(86400)
    except KeyboardInterrupt:
        server.stop(0)


