import subprocess
import os


def generate_certificates():
    # Generate CA private key
    subprocess.run([
        'openssl', 'genrsa', '-out', 'ca.key', '4096'
    ])
    
    # Generate CA certificate
    subprocess.run([
        'openssl', 'req', '-new', '-x509', '-key', 'ca.key',
        '-sha256', '-subj', '/C=US/ST=CA/O=MyOrg/CN=MyCA',
        '-days', '365', '-out', 'ca.crt'
    ])
    
    # Generate server private key
    subprocess.run([
        'openssl', 'genrsa', '-out', 'server.key', '4096'
    ])
    
    # Generate server CSR
    subprocess.run([
        'openssl', 'req', '-new', '-key', 'server.key',
        '-subj', '/C=US/ST=CA/O=MyOrg/CN=localhost',
        '-out', 'server.csr'
    ])
    
    # Sign server certificate
    subprocess.run([
        'openssl', 'x509', '-req', '-in', 'server.csr',
        '-CA', 'ca.crt', '-CAkey', 'ca.key', '-CAcreateserial',
        '-out', 'server.crt', '-days', '365', '-sha256'
    ])
    
    # Generate client private key
    subprocess.run([
        'openssl', 'genrsa', '-out', 'client.key', '4096'
    ])
    
    # Generate client CSR
    subprocess.run([
        'openssl', 'req', '-new', '-key', 'client.key',
        '-subj', '/C=US/ST=CA/O=MyOrg/CN=client',
        '-out', 'client.csr'
    ])
    
    # Sign client certificate
    subprocess.run([
        'openssl', 'x509', '-req', '-in', 'client.csr',
        '-CA', 'ca.crt', '-CAkey', 'ca.key', '-CAcreateserial',
        '-out', 'client.crt', '-days', '365', '-sha256'
    ])
    
    # Clean up CSR files
    os.remove('server.csr')
    os.remove('client.csr')
    
    print("TLS certificates generated successfully")


if __name__ == '__main__':
    generate_certificates()